export type Cell = [number, number];

const isNeighbor = ([x1, y1]: Cell, [x2, y2]: Cell): boolean => {
  const dx = Math.abs(x1 - x2);
  const dy = Math.abs(y1 - y2);
  const isSameCell = dx === 0 && dy === 0;
  return !isSameCell && dx <= 1 && dy <= 1;
};

const countLivingNeighbors = (cell: Cell, livingCells: Cell[]): number =>
  livingCells.filter((other) => isNeighbor(cell, other)).length;

const survivesNextGeneration = (cell: Cell, livingCells: Cell[]): boolean => {
  const neighbors = countLivingNeighbors(cell, livingCells);
  return neighbors === 2 || neighbors === 3;
};

const cellKey = ([x, y]: Cell): string => `${x},${y}`;

const getDeadNeighbors = (livingCells: Cell[]): Cell[] => {
  const livingKeys = new Set(livingCells.map(cellKey));
  const deadNeighbors = new Map<string, Cell>();
  for (const [x, y] of livingCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const candidate: Cell = [x + dx, y + dy];
        const key = cellKey(candidate);
        if (!livingKeys.has(key)) {
          deadNeighbors.set(key, candidate);
        }
      }
    }
  }
  return Array.from(deadNeighbors.values());
};

const isReborn = (cell: Cell, livingCells: Cell[]): boolean =>
  countLivingNeighbors(cell, livingCells) === 3;

export const nextGeneration = (livingCells: Cell[]): Cell[] => {
  const survivors = livingCells.filter((cell) => survivesNextGeneration(cell, livingCells));
  const reborn = getDeadNeighbors(livingCells).filter((cell) => isReborn(cell, livingCells));
  return [...survivors, ...reborn];
};

