export type Cell = [number, number];

const isNeighbor = ([x1, y1]: Cell, [x2, y2]: Cell): boolean => {
  const dx = Math.abs(x1 - x2);
  const dy = Math.abs(y1 - y2);
  const isSameCell = dx === 0 && dy === 0;
  return !isSameCell && dx <= 1 && dy <= 1;
};

const countLivingNeighbors = (cell: Cell, livingCells: Cell[]): number =>
  livingCells.filter((other) => isNeighbor(cell, other)).length;

const cellKey = ([x, y]: Cell): string => `${x},${y}`;

const getCandidateCells = (livingCells: Cell[]): Cell[] => {
  const candidates = new Map<string, Cell>();
  for (const [x, y] of livingCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        const candidate: Cell = [x + dx, y + dy];
        candidates.set(cellKey(candidate), candidate);
      }
    }
  }
  return Array.from(candidates.values());
};

const livesInNextGeneration = (cell: Cell, livingCells: Cell[]): boolean => {
  const neighbors = countLivingNeighbors(cell, livingCells);
  const isAlive = livingCells.some((living) => cellKey(living) === cellKey(cell));
  return isAlive ? neighbors === 2 || neighbors === 3 : neighbors === 3;
};

export const nextGeneration = (livingCells: Cell[]): Cell[] =>
  getCandidateCells(livingCells).filter((cell) => livesInNextGeneration(cell, livingCells));
